function generateRandomToken(bytes = 48) {
  return crypto.randomBytes(bytes).toString('hex');
}

function generateAuthorizationCode() {
  return crypto.randomBytes(32).toString('hex');
}

function generateAccessToken(userId, clientId, scope) {
  return jwt.sign(
    {
      sub: userId,
      client_id: clientId,
      scope: scope,
      type: 'access_token',
      jti: uuidv4(),
    },
    CONFIG.ACCESS_TOKEN_SECRET,
    { expiresIn: CONFIG.ACCESS_TOKEN_EXPIRY }
  );
}

function generateRefreshToken() {
  return generateRandomToken(64);
}

function verifyAccessToken(token) {
  try {
    return jwt.verify(token, CONFIG.ACCESS_TOKEN_SECRET);
  } catch (err) {
    return null;
  }
}

// ============================================================
// Redis Key Helpers
// ============================================================

const REDIS_KEYS = {
  refreshToken: (token) => `refresh_token:${token}`,
  authCode: (code) => `auth_code:${code}`,
  userRefreshTokens: (userId) => `user_refresh_tokens:${userId}`,
  clientRefreshTokens: (clientId) => `client_refresh_tokens:${clientId}`,
  revokedToken: (jti) => `revoked_access_token:${jti}`,
};

// ============================================================
// Refresh Token Storage (Redis)
// ============================================================

async function storeRefreshToken(refreshToken, tokenData) {
  const key = REDIS_KEYS.refreshToken(refreshToken);
  const data = {
    ...tokenData,
    created_at: Date.now(),
    last_used_at: Date.now(),
    use_count: 0,
  };

  // Store the refresh token with 1-year TTL
  await redis.set(key, JSON.stringify(data), 'EX', CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);

  // Track tokens per user for potential revocation
  await redis.sadd(REDIS_KEYS.userRefreshTokens(tokenData.user_id), refreshToken);
  await redis.expire(REDIS_KEYS.userRefreshTokens(tokenData.user_id), CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);

  // Track tokens per client
  await redis.sadd(REDIS_KEYS.clientRefreshTokens(tokenData.client_id), refreshToken);
  await redis.expire(REDIS_KEYS.clientRefreshTokens(tokenData.client_id), CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);

  return data;
}

async function getRefreshToken(refreshToken) {
  const key = REDIS_KEYS.refreshToken(refreshToken);
  const data = await redis.get(key);
  if (!data) return null;
  return JSON.parse(data);
}

async function updateRefreshTokenUsage(refreshToken, tokenData) {
  const key = REDIS_KEYS.refreshToken(refreshToken);
  tokenData.last_used_at = Date.now();
  tokenData.use_count = (tokenData.use_count || 0) + 1;

  // Get remaining TTL to preserve it
  const ttl = await redis.ttl(key);
  if (ttl > 0) {
    await redis.set(key, JSON.stringify(tokenData), 'EX', ttl);
  }
  return tokenData;
}

async function revokeRefreshToken(refreshToken) {
  const key = REDIS_KEYS.refreshToken(refreshToken);
  const data = await redis.get(key);
  if (data) {
    const tokenData = JSON.parse(data);
    await redis.srem(REDIS_KEYS.userRefreshTokens(tokenData.user_id), refreshToken);
    await redis.srem(REDIS_KEYS.clientRefreshTokens(tokenData.client_id), refreshToken);
  }
  await redis.del(key);
}

async function revokeAllUserRefreshTokens(userId) {
  const tokens = await redis.smembers(REDIS_KEYS.userRefreshTokens(userId));
  const pipeline = redis.pipeline();
  for (const token of tokens) {
    pipeline.del(REDIS_KEYS.refreshToken(token));
  }
  pipeline.del(REDIS_KEYS.userRefreshTokens(userId));
  await pipeline.exec();
  return tokens.length;
}

