async function storeAuthorizationCode(code, codeData) {
  const key = REDIS_KEYS.authCode(code);
  await redis.set(key, JSON.stringify(codeData), 'EX', CONFIG.AUTHORIZATION_CODE_EXPIRY_SECONDS);
}

async function getAndDeleteAuthorizationCode(code) {
  const key = REDIS_KEYS.authCode(code);
  const data = await redis.get(key);
  if (!data) return null;
  await redis.del(key); // Authorization codes are single-use
  return JSON.parse(data);
}

