// POST /authorize - Handle authorization (login + consent)
app.post('/authorize', async (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state, username, password, action } = req.body;

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }

  const finalRedirectUri = redirect_uri || client.redirect_uris[0];

  if (action === 'deny') {
    const params = new URLSearchParams({ error: 'access_denied', state: state || '' });
    return res.redirect(`${finalRedirectUri}?${params}`);
  }

  // Authenticate user
  let authenticatedUser = null;
  for (const [, user] of users) {
    if (user.username === username) {
      const match = await bcrypt.compare(password, user.password_hash);
      if (match) {
        authenticatedUser = user;
      }
      break;
    }
  }

  if (!authenticatedUser) {
    return res.status(401).send('Invalid credentials. <a href="javascript:history.back()">Try again</a>');
  }

  // Validate requested scopes
  const requestedScopes = scope ? scope.split(' ').filter(Boolean) : ['read'];
  const validScopes = requestedScopes.filter((s) => client.scopes.includes(s));

  // Generate authorization code
  const code = generateAuthorizationCode();
  await storeAuthorizationCode(code, {
    client_id: client_id,
    user_id: authenticatedUser.id,
    redirect_uri: finalRedirectUri,
    scope: validScopes.join(' '),
    created_at: Date.now(),
  });

  const params = new URLSearchParams({
    code: code,
    ...(state && { state }),
  });

  res.redirect(`${finalRedirectUri}?${params}`);
});

